namespace sv_58f660801d75401795b7e5a49bf675a7.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public sealed class ThemeState
{
    public Theme Theme { get; init; } = Theme.System;
    public string AccentColor { get; init; } = "#0d6efd";
}

/// <summary>
/// Scoped service — each SignalR circuit (user) gets its own instance.
/// Static SSR components cannot subscribe; only interactive components can.
/// </summary>
public sealed class ThemeService
{
    private ThemeState _state = new();

    public ThemeState Current => _state;

    public event Action? OnChange;

    public void SetTheme(Theme theme)
    {
        _state = _state with { Theme = theme };
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        _state = _state with { AccentColor = color };
        OnChange?.Invoke();
    }

    public void Update(Theme theme, string accentColor)
    {
        _state = new ThemeState { Theme = theme, AccentColor = accentColor };
        OnChange?.Invoke();
    }
}

@* Interactive island that lives in the static layout.
   It subscribes to ThemeService and re-renders its subtree on changes. *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<div class="theme-root" data-theme="@ThemeName" style="--accent-color: @ThemeService.Current.AccentColor;">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    private string ThemeName => ThemeService.Current.Theme switch
    {
        Theme.Dark => "dark",
        Theme.Light => "light",
        _ => "system"
    };

    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeService.OnChange -= HandleThemeChanged;
}

@* Small interactive island placed in the static header.
   Shows the current theme and lets the user cycle through options. *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme" title="Current theme: @Label">
    @Icon @Label
</button>

@code {
    private string Label => ThemeService.Current.Theme switch
    {
        Theme.Dark => "Dark",
        Theme.Light => "Light",
        _ => "System"
    };

    private string Icon => ThemeService.Current.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.Light => "☀️",
        _ => "💻"
    };

    private void CycleTheme()
    {
        var next = ThemeService.Current.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        ThemeService.SetTheme(next);
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeService.OnChange -= HandleThemeChanged;
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                var active = t == _theme ? "active" : "";
                <button class="btn btn-outline-primary @active" @onclick="() => SelectTheme(t)">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@_accentColor" @onchange="OnAccentColorChange" />
            <span style="color: var(--accent-color); font-weight: bold;">@_accentColor</span>
        </div>

        <button class="btn btn-primary" @onclick="Save">Save</button>

        @if (_saved)
        {
            <span class="text-success ms-2">✓ Saved</span>
        }
    </div>
</div>

@code {
    private Theme _theme;
    private string _accentColor = "#0d6efd";
    private bool _saved;

    protected override void OnInitialized()
    {
        _theme = ThemeService.Current.Theme;
        _accentColor = ThemeService.Current.AccentColor;
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void SelectTheme(Theme theme) => _theme = theme;

    private void OnAccentColorChange(ChangeEventArgs e)
    {
        _accentColor = e.Value?.ToString() ?? _accentColor;
    }

    private void Save()
    {
        ThemeService.Update(_theme, _accentColor);
        _saved = true;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(() =>
        {
            _theme = ThemeService.Current.Theme;
            _accentColor = ThemeService.Current.AccentColor;
            StateHasChanged();
        });
    }

    public void Dispose() => ThemeService.OnChange -= HandleThemeChanged;
}

