@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                var active = t == _theme ? "active" : "";
                <button class="btn btn-outline-primary @active" @onclick="() => SelectTheme(t)">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@_accentColor" @onchange="OnAccentColorChange" />
            <span style="color: var(--accent-color); font-weight: bold;">@_accentColor</span>
        </div>

        <button class="btn btn-primary" @onclick="Save">Save</button>

        @if (_saved)
        {
            <span class="text-success ms-2">✓ Saved</span>
        }
    </div>
</div>

@code {
    private Theme _theme;
    private string _accentColor = "#0d6efd";
    private bool _saved;

    protected override void OnInitialized()
    {
        _theme = ThemeService.Current.Theme;
        _accentColor = ThemeService.Current.AccentColor;
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void SelectTheme(Theme theme) => _theme = theme;

    private void OnAccentColorChange(ChangeEventArgs e)
    {
        _accentColor = e.Value?.ToString() ?? _accentColor;
    }

    private void Save()
    {
        ThemeService.Update(_theme, _accentColor);
        _saved = true;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(() =>
        {
            _theme = ThemeService.Current.Theme;
            _accentColor = ThemeService.Current.AccentColor;
            StateHasChanged();
        });
    }

    public void Dispose() => ThemeService.OnChange -= HandleThemeChanged;
}

